set -e

REVISION=${1:-current}

BRANCH_NAME="revision/${REVISION}"
git branch ${BRANCH_NAME} | true
git checkout ${BRANCH_NAME}

npm run full-build ${REVISION}

git add src/index.ts
git commit -m "revision ${REVISION}" | true
npm version minor
git tag -f ${REVISION}
git push --set-upstream origin ${BRANCH_NAME}
git push --tags

npm publish --tag ${REVISION} --access public